import java.util.*;

class Solution {
    public int lengthOfLongestSubstring(String s) {
        int[] last = new int[128];
        Arrays.fill(last, -1);
        int left = 0;
        int best = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (last[c] >= left) {
                left = last[c] + 1;
            }
            last[c] = i;
            int len = i - left + 1;
            if (len > best) {
                best = len;
            }
        }
        return best;
    }
}

