class Solution {
    public TreeNode buildTree(int[] preorder, int[] inorder) {
        Map<Integer, Integer> idx = new HashMap<>();
        for (int i = 0; i < inorder.length; i++) {
            idx.put(inorder[i], i);
        }
        return build(preorder, 0, preorder.length - 1, inorder, 0, inorder.length - 1, idx);
    }
    private TreeNode build(int[] preorder, int pl, int pr, int[] inorder, int il, int ir, Map<Integer, Integer> idx) {
        if (pl > pr) {
            return null;
        }
        int rootVal = preorder[pl];
        int k = idx.get(rootVal);
        int leftSize = k - il;
        TreeNode root = new TreeNode(rootVal);
        root.left = build(preorder, pl + 1, pl + leftSize, inorder, il, k - 1, idx);
        root.right = build(preorder, pl + leftSize + 1, pr, inorder, k + 1, ir, idx);
        return root;
    }
}

